import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"模拟账户","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/account-types/paper-trading.md","filePath":"zh-CN/account/account-types/paper-trading.md"}'),p={name:"account/account-types/paper-trading.md"};function n(c,a,i,d,s,l){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="模拟账户" tabindex="-1">模拟账户 <a class="header-anchor" href="#模拟账户" aria-label="Permalink to &quot;模拟账户&quot;">​</a></h1><p>模拟账户虚拟练习资金额度、开通方式、注销与重置规则。</p><h2 id="账户介绍" tabindex="-1">账户介绍 <a class="header-anchor" href="#账户介绍" aria-label="Permalink to &quot;账户介绍&quot;">​</a></h2><p>模拟账户是长桥提供的辅助练习工具，不涉及真实交易。账户号以 LBPT 开头。无需走具体的开户流程和开户审核。</p><h2 id="开通方式" tabindex="-1">开通方式 <a class="header-anchor" href="#开通方式" aria-label="Permalink to &quot;开通方式&quot;">​</a></h2><p>在长桥 App 资产页面左上角，切换账户，选择模拟账户进行申请，申请后大约 5 分钟内开通。桌面客户端操作方式相同。</p><p>开通自带虚拟练习资金：800,000 HKD。</p><h2 id="注销与重置" tabindex="-1">注销与重置 <a class="header-anchor" href="#注销与重置" aria-label="Permalink to &quot;注销与重置&quot;">​</a></h2><p>注销路径：长桥 App - 我的 - 设置 - 账户设置，滑到最下面可以直接注销模拟账户。</p><p>注销后重新申请开通会重置虚拟练习资金。</p><p>可注销次数：一个月一次。</p>',11)])])}const _=e(p,[["render",n]]);export{u as __pageData,_ as default};
